import { zValidator } from "@hono/zod-validator";
import { type AnyDrizzleDB, buildSchema } from "drizzle-graphql";
import { graphql } from "graphql";
import type { GlobalPlugin } from "honohub";
import { z } from "zod";
import type { GraphQLEditorProps } from "./playground";

export const graphQLBodyValidation = z.object({
  operationName: z.string().optional(),
  query: z.string(),
  variables: z.record(z.string(), z.any()).optional(),
});

export type GraphQLPluginConfig = {
  route?: string;
  playground?:
    | boolean
    | {
        route?: string;
        graphQLEndpoint?: string;
      };
};

const defaultPlaygroundOptions = {
  route: "/playground",
  graphQLEndpoint: "/graphql",
};

export function useGraphQL<Database extends AnyDrizzleDB<any>>(
  options: GraphQLPluginConfig = {},
): GlobalPlugin<Database> {
  const { route = "/graphql" } = options;

  return {
    name: "honohub-graphql",
    bootstrap(props) {
      const { schema } = buildSchema(props.config.db);

      props.app.post(
        route,
        zValidator("json", graphQLBodyValidation),
        async (c) => {
          const data = c.req.valid("json");

          const response = await graphql({
            schema: schema,
            source: data.query,
          });

          return c.json(response);
        },
      );

      return props.app;
    },
    register(config) {
      if (!options.playground) return undefined;

      const { route: playgroundRoute, graphQLEndpoint } = {
        ...defaultPlaygroundOptions,
        ...(typeof options.playground !== "boolean" ? options.playground : {}),
      };

      return {
        ...config,
        routes: [
          ...config.routes,
          {
            icon: "CodeBracketSquareIcon",
            label: "GraphQL Editor",
            path: playgroundRoute,
            import: "@honohub/graphql/playground",
            props(config): GraphQLEditorProps {
              return {
                endpoint: graphQLEndpoint ?? `${config.serverUrl}/graphql`,
              };
            },
          },
        ],
      };
    },
  };
}

import { Hono } from "hono";
import { cors } from "hono/cors";
import { HTTPException } from "hono/http-exception";

import { type ErrorResponse } from "@/shared/types";

import type { Context } from "./context";
import { lucia } from "./lucia";
import { authRouter } from "./routes/auth";
import { commentsRouter } from "./routes/comments";
import { postRouter } from "./routes/posts";
import { serveStatic } from "hono/bun";

const app = new Hono<Context>();

app.use("*", cors(), async (c, next) => {
  const sessionId = lucia.readSessionCookie(c.req.header("Cookie") ?? "");
  if (!sessionId) {
    c.set("user", null);
    c.set("session", null);
    return next();
  }

  const { session, user } = await lucia.validateSession(sessionId);
  if (session && session.fresh) {
    c.header("Set-Cookie", lucia.createSessionCookie(session.id).serialize(), {
      append: true,
    });
  }
  if (!session) {
    c.header("Set-Cookie", lucia.createBlankSessionCookie().serialize(), {
      append: true,
    });
  }
  c.set("session", session);
  c.set("user", user);
  return next();
});

// eslint-disable-next-line @typescript-eslint/no-unused-vars
const routes = app
  .basePath("/api")
  .route("/auth", authRouter)
  .route("/posts", postRouter)
  .route("/comments", commentsRouter);

app.onError((err, c) => {
  if (err instanceof HTTPException) {
    const errResponse =
      err.res ??
      c.json<ErrorResponse>(
        {
          success: false,
          error: err.message,
          isFormError:
            err.cause && typeof err.cause === "object" && "form" in err.cause
              ? err.cause.form === true
              : false,
        },
        err.status,
      );
    return errResponse;
  }

  return c.json<ErrorResponse>(
    {
      success: false,
      error:
        process.env.NODE_ENV === "production"
          ? "Interal Server Error"
          : (err.stack ?? err.message),
    },
    500,
  );
});

app.get("*", serveStatic({ root: "./frontend/dist" }));
app.get("*", serveStatic({ path: "./frontend/dist/index.html" }));

export default {
  port: process.env["PORT"] || 3000,
  hostname: "0.0.0.0",
  fetch: app.fetch,
};

console.log("Server Running on port", process.env["PORT"] || 3000);
export type ApiRoutes = typeof routes;

import { eq } from 'drizzle-orm'
import { STATUS_CODES } from 'node:http'

import type { AppRouteHandler } from '@/lib/types.js'

import { db } from '@/db/index.js'
import { tasks } from '@/db/schema/tasks.js'
import { ZOD_ERROR_CODES, ZOD_ERROR_MESSAGES } from '@/lib/constants.js'

import type { CreateRoute, GetOneRoute, ListRoute, PatchRoute, RemoveRoute } from './tasks.routes.js'

export const list: AppRouteHandler<ListRoute> = async (c) => {
  const tasks = await db.query.tasks.findMany()
  return c.json(tasks)
}

export const create: AppRouteHandler<CreateRoute> = async (c) => {
  const taskPayload = c.req.valid('json')
  const [insertedTask] = await db.insert(tasks).values(taskPayload).returning()
  return c.json(insertedTask, 200)
}

export const getOne: AppRouteHandler<GetOneRoute> = async (c) => {
  const { id } = c.req.valid('param')

  const task = await db.query.tasks.findFirst({
    where(fields, operators) {
      return operators.eq(fields.id, id)
    },
  })

  if (!task) {
    const statusCode = 404
    return c.json({ message: STATUS_CODES[statusCode]! }, statusCode)
  }

  return c.json(task, 200)
}

export const patch: AppRouteHandler<PatchRoute> = async (c) => {
  const { id } = c.req.valid('param')
  const updates = c.req.valid('json')

  if (Object.keys(updates).length === 0) {
    return c.json(
      {
        success: false,
        error: {
          issues: [
            {
              code: ZOD_ERROR_CODES.INVALID_UPDATE,
              path: [],
              message: ZOD_ERROR_MESSAGES.NO_UPDATE,
            },
          ],
          name: 'ZodError',
        },
      },
      422,
    )
  }

  const [task] = await db.update(tasks)
    .set(updates)
    .where(eq(tasks.id, id))
    .returning()

  if (!task) {
    const statusCode = 404
    return c.json({ message: STATUS_CODES[statusCode]! }, statusCode)
  }

  return c.json(task, 200)
}

export const remove: AppRouteHandler<RemoveRoute> = async (c) => {
  const { id } = c.req.valid('param')

  const deletedResult = await db.delete(tasks)
    .where(eq(tasks.id, id))
    .returning()

  if (deletedResult.length === 0) {
    const statusCode = 404
    return c.json({ message: STATUS_CODES[statusCode]! }, statusCode)
  }

  return c.body(null, 204)
}

import { eq } from "drizzle-orm";
import * as HttpStatusCodes from "stoker/http-status-codes";
import * as HttpStatusPhrases from "stoker/http-status-phrases";

import type { AppRouteHandler } from "@/lib/types";

import db from "@/db";
import { tasks } from "@/db/schema";
import { ZOD_ERROR_CODES, ZOD_ERROR_MESSAGES } from "@/lib/constants";

import type { CreateRoute, GetOneRoute, ListRoute, PatchRoute, RemoveRoute } from "./tasks.routes";

export const list: AppRouteHandler<ListRoute> = async (c) => {
  const tasks = await db.query.tasks.findMany();
  return c.json(tasks);
};

export const create: AppRouteHandler<CreateRoute> = async (c) => {
  const task = c.req.valid("json");
  const [inserted] = await db.insert(tasks).values(task).returning();
  return c.json(inserted, HttpStatusCodes.OK);
};

export const getOne: AppRouteHandler<GetOneRoute> = async (c) => {
  const { id } = c.req.valid("param");
  const task = await db.query.tasks.findFirst({
    where(fields, operators) {
      return operators.eq(fields.id, id);
    },
  });

  if (!task) {
    return c.json(
      {
        message: HttpStatusPhrases.NOT_FOUND,
      },
      HttpStatusCodes.NOT_FOUND,
    );
  }

  return c.json(task, HttpStatusCodes.OK);
};

export const patch: AppRouteHandler<PatchRoute> = async (c) => {
  const { id } = c.req.valid("param");
  const updates = c.req.valid("json");

  if (Object.keys(updates).length === 0) {
    return c.json(
      {
        success: false,
        error: {
          issues: [
            {
              code: ZOD_ERROR_CODES.INVALID_UPDATES,
              path: [],
              message: ZOD_ERROR_MESSAGES.NO_UPDATES,
            },
          ],
          name: "ZodError",
        },
      },
      HttpStatusCodes.UNPROCESSABLE_ENTITY,
    );
  }

  const [task] = await db.update(tasks)
    .set(updates)
    .where(eq(tasks.id, id))
    .returning();

  if (!task) {
    return c.json(
      {
        message: HttpStatusPhrases.NOT_FOUND,
      },
      HttpStatusCodes.NOT_FOUND,
    );
  }

  return c.json(task, HttpStatusCodes.OK);
};

export const remove: AppRouteHandler<RemoveRoute> = async (c) => {
  const { id } = c.req.valid("param");
  const result = await db.delete(tasks)
    .where(eq(tasks.id, id));

  if (result.rowsAffected === 0) {
    return c.json(
      {
        message: HttpStatusPhrases.NOT_FOUND,
      },
      HttpStatusCodes.NOT_FOUND,
    );
  }

  return c.body(null, HttpStatusCodes.NO_CONTENT);
};

import type { ReadStream } from 'node:fs'
import { versions } from 'node:process'
import { Readable } from 'node:stream'

// In Node.js versions that do not have the following PR applied, using Readable.toWeb may cause unexpected exceptions.
// https://github.com/nodejs/node/pull/54206
const pr54206Applied = () => {
  const [major, minor] = versions.node.split('.').map((component) => parseInt(component))
  return major >= 23 || (major === 22 && minor >= 7) || (major === 20 && minor >= 18)
}
const useReadableToWeb = pr54206Applied()

export const createStreamBody = (
  stream: ReadStream,
  useNativeReadableToWeb = useReadableToWeb
): ReadableStream<Uint8Array> => {
  if (useNativeReadableToWeb) {
    return Readable.toWeb(stream) as ReadableStream<Uint8Array>
  }

  let controller: ReadableStreamDefaultController<Uint8Array> | undefined
  let settled = false

  const cleanup = () => {
    stream.off('data', onData)
    stream.off('error', onError)
    stream.off('end', onTerminate)
    stream.off('close', onTerminate)
  }

  const settle = (callback?: () => void) => {
    if (settled) {
      return
    }
    settled = true
    cleanup()
    callback?.()
  }

  const onData = (chunk: Buffer | string) => {
    if (settled || !controller) {
      return
    }
    // createReadStream is called without `encoding`, so chunks are always Buffer.
    controller.enqueue(chunk as Buffer)
    if ((controller.desiredSize ?? 0) <= 0) {
      stream.pause()
    }
  }

  const onError = (error: Error) => {
    settle(() => {
      controller?.error(error)
    })
  }

  const onTerminate = () => {
    settle(() => {
      controller?.close()
    })
  }

  return new ReadableStream<Uint8Array>({
    start(streamController) {
      controller = streamController
      stream.on('data', onData)
      stream.on('error', onError)
      stream.on('end', onTerminate)
      stream.on('close', onTerminate)
      stream.pause()
    },

    pull() {
      if (!settled) {
        stream.resume()
      }
    },

    cancel() {
      settle()
      // Suppress late `error` emitted between destroy() and the terminal `close`.
      const ignoreError = () => {}
      stream.on('error', ignoreError)
      stream.once('close', () => stream.off('error', ignoreError))
      stream.destroy()
    },
  })
}

import { z } from "zod";
import { contentJson } from "../contentTypes";
import { InputValidationException } from "../exceptions";
import { OpenAPIRoute } from "../route";
import { MetaGenerator, type MetaInput, metaSchemaProps, type O } from "./types";

export class CreateEndpoint<HandleArgs extends Array<object> = Array<object>> extends OpenAPIRoute<HandleArgs> {
  // @ts-expect-error
  _meta: MetaInput;

  get meta() {
    return MetaGenerator(this._meta);
  }

  getSchema() {
    const bodyParameters = this.meta.fields.omit(
      (this.params.urlParams || []).reduce((a, v) => ({ ...a, [v]: true }), {}),
    );
    const pathParameters = this.meta.fields.pick(
      (this.params.urlParams || []).reduce((a, v) => ({ ...a, [v]: true }), {}),
    );

    return {
      request: {
        body: contentJson(bodyParameters),
        params: Object.keys(pathParameters.shape).length ? pathParameters : undefined,
        ...this.schema?.request,
      },
      responses: {
        "201": {
          description: "Returns the created Object",
          ...contentJson(
            z.object({
              success: z.boolean(),
              result: this.meta.model.serializerSchema,
            }),
          ),
          ...this.schema?.responses?.[201],
        },
        ...InputValidationException.schema(),
        ...this.schema?.responses,
      },
      ...metaSchemaProps(this._meta),
      ...this.schema,
    };
  }

  async getObject(): Promise<O<typeof this._meta>> {
    const data = await this.getValidatedData();

    const newData: any = {
      ...(data.body as object),
    };

    for (const param of this.params.urlParams) {
      newData[param] = (data.params as any)[param];
    }

    return newData;
  }

  async before(data: O<typeof this._meta>): Promise<O<typeof this._meta>> {
    return data;
  }

  async after(data: O<typeof this._meta>): Promise<O<typeof this._meta>> {
    return data;
  }

  async create(data: O<typeof this._meta>): Promise<O<typeof this._meta>> {
    return data;
  }

  async handle(..._args: HandleArgs) {
    let obj = await this.getObject();

    obj = await this.before(obj);

    obj = await this.create(obj);

    obj = await this.after(obj);

    return Response.json(
      {
        success: true,
        result: this.meta.model.serializer(obj as object, { filters: [] }),
      },
      { status: 201 },
    );
  }
}

import { eq, sql } from "drizzle-orm";
import { HTTPException } from "hono/http-exception";
import db from "../../database";
import { columnTable } from "../../database/schema";
import { VIRTUAL_STATUSES } from "../../task/validate-task-fields";

function toSlug(name: string): string {
  return name
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

async function createColumn({
  projectId,
  name,
  icon,
  color,
  isFinal,
}: {
  projectId: string;
  name: string;
  icon?: string;
  color?: string;
  isFinal?: boolean;
}) {
  const slug = toSlug(name);

  if (!slug) {
    throw new HTTPException(400, {
      message: "Column name must contain at least one alphanumeric character",
    });
  }

  if ((VIRTUAL_STATUSES as readonly string[]).includes(slug)) {
    throw new HTTPException(409, {
      message: `Column slug "${slug}" is reserved for virtual task statuses`,
    });
  }

  const existing = await db
    .select({ id: columnTable.id })
    .from(columnTable)
    .where(
      sql`${columnTable.projectId} = ${projectId} AND ${columnTable.slug} = ${slug}`,
    );

  if (existing.length > 0) {
    throw new HTTPException(409, {
      message: `Column with slug "${slug}" already exists in this project`,
    });
  }

  const [maxPos] = await db
    .select({
      maxPosition: sql<number>`COALESCE(MAX(${columnTable.position}), -1)`,
    })
    .from(columnTable)
    .where(eq(columnTable.projectId, projectId));

  const position = (maxPos?.maxPosition ?? -1) + 1;

  const [created] = await db
    .insert(columnTable)
    .values({
      projectId,
      name,
      slug,
      position,
      icon: icon || null,
      color: color || null,
      isFinal: isFinal ?? false,
    })
    .returning();

  if (!created) {
    throw new HTTPException(500, { message: "Failed to create column" });
  }

  return created;
}

export default createColumn;

import { eq } from "drizzle-orm";
import { HTTPException } from "hono/http-exception";
import db from "../../database";
import { labelTable, projectTable, taskTable } from "../../database/schema";
import { publishEvent } from "../../events";
import {
  removeLabelFromGitea,
  syncLabelToGitea,
} from "../../plugins/gitea/utils/sync-label-to-gitea";
import {
  removeLabelFromGitHub,
  syncLabelToGitHub,
} from "../../plugins/github/utils/sync-label-to-github";

async function assignLabelToTask(id: string, taskId: string, userId: string) {
  const label = await db.query.labelTable.findFirst({
    where: (label, { eq }) => eq(label.id, id),
  });

  if (!label) {
    throw new HTTPException(404, {
      message: "Label not found",
    });
  }

  const [task] = await db
    .select({
      id: taskTable.id,
      projectId: taskTable.projectId,
      workspaceId: projectTable.workspaceId,
    })
    .from(taskTable)
    .innerJoin(projectTable, eq(taskTable.projectId, projectTable.id))
    .where(eq(taskTable.id, taskId))
    .limit(1);

  if (!task) {
    throw new HTTPException(404, {
      message: "Task not found",
    });
  }

  if (label.workspaceId && label.workspaceId !== task.workspaceId) {
    throw new HTTPException(400, {
      message: "Label and task must belong to the same workspace",
    });
  }

  const [updatedLabel] = await db
    .update(labelTable)
    .set({ taskId })
    .where(eq(labelTable.id, id))
    .returning();

  if (!updatedLabel) {
    throw new HTTPException(500, {
      message: "Failed to attach label to task",
    });
  }

  if (label.taskId && label.taskId !== taskId) {
    removeLabelFromGitHub(label.taskId, label.name).catch((error) => {
      console.error("Failed to remove label from GitHub:", error);
    });
    removeLabelFromGitea(label.taskId, label.name).catch((error) => {
      console.error("Failed to remove label from Gitea:", error);
    });
  }

  syncLabelToGitHub(taskId, updatedLabel.name, updatedLabel.color).catch(
    (error) => {
      console.error("Failed to sync label to GitHub:", error);
    },
  );
  syncLabelToGitea(taskId, updatedLabel.name, updatedLabel.color).catch(
    (error) => {
      console.error("Failed to sync label to Gitea:", error);
    },
  );

  await publishEvent("task.label_assigned", {
    label: updatedLabel,
    task,
    projectId: task.projectId,
    taskId: task.id,
    userId,
    type: "label_assigned",
  });

  return updatedLabel;
}

export default assignLabelToTask;

import type { z } from "zod";
import type { AnyZodObject, OrderByDirection, SetRequired } from "../types";

export type FilterCondition = {
  field: string;
  operator: string;
  value: string | number | boolean | null;
};

export type ListFilters = {
  filters: Array<FilterCondition>;
  options: {
    page?: number;
    per_page?: number;
    order_by?: string;
    order_by_direction?: OrderByDirection;
    [key: string]: unknown;
  };
};

export type Filters = {
  filters: Array<FilterCondition>;
};

export type UpdateFilters = {
  filters: Array<FilterCondition>;
  updatedData: Record<string, any>;
};

export type UpdatedData = {
  updatedData: Record<string, any>;
};

export type SerializerContext = {
  filters?: Array<FilterCondition>;
  options?: {
    page?: number;
    per_page?: number;
    order_by?: string;
    order_by_direction?: OrderByDirection;
    [key: string]: unknown;
  };
};

export type Model = {
  tableName: string;
  schema: AnyZodObject;
  primaryKeys: Array<string>;
  serializer?: (obj: object, context?: SerializerContext) => object;
  serializerSchema?: AnyZodObject;
};

export type ModelComplete = SetRequired<Model, "serializer" | "serializerSchema">;

export type MetaInput = {
  model: Model;
  fields?: AnyZodObject;
  pathParameters?: Array<string>;
  tags?: Array<string>;
};

export type Meta = {
  model: ModelComplete;
  fields: AnyZodObject;
  tags?: Array<string>;
};

export type O<M extends MetaInput> = z.infer<M["model"]["schema"]>;

export type ListResult<O> = {
  result: Array<O>;
};

export function MetaGenerator(meta: MetaInput) {
  return {
    fields: meta.fields ?? meta.model.schema,
    model: {
      serializer: (obj: any, _context?: SerializerContext): any => obj,
      serializerSchema: meta.model.schema,
      ...meta.model,
    },
    pathParameters: meta.pathParameters ?? null,
    tags: meta.tags,
  };
}

export function metaSchemaProps(meta: MetaInput): Record<string, unknown> {
  return {
    ...(meta.tags?.length ? { tags: meta.tags } : {}),
  };
}

export type Logger = {
  log: (...args: any[]) => void;
  info: (...args: any[]) => void;
  warn: (...args: any[]) => void;
  error: (...args: any[]) => void;
  debug: (...args: any[]) => void;
  trace: (...args: any[]) => void;
};

import { z } from '@hono/zod-openapi';
import type { Context } from 'hono';
import { nanoid } from 'nanoid';
import type { ZodIssue } from 'zod';

export const InvalidInputResponseSchema = z.object({
  errors: z.array(
    z.object({
      // https://jsonapi.org/format/#error-objects
      id: z.string().optional().openapi({
        example: '68fd63j5',
      }),
      status: z.number().int().openapi({
        example: 400,
      }),
      code: z.string().openapi({
        example: 'INVALID_INPUT',
      }),
      title: z.string().openapi({
        example: 'Invalid Input',
      }),
      details: z.string().optional().openapi({
        example: 'The input is invalid',
      }),
      meta: z
        .object({
          ZodIssue: z
            .object({})
            .optional()
            .openapi({
              example: {
                code: 'too_small',
                minimum: 3,
                type: 'string',
                inclusive: true,
                exact: false,
                message: 'String must contain at least 3 character(s)',
                path: ['username'],
              },
            }),
        })
        .optional()
        .openapi({}),
      source: z.object({
        pointer: z.string().optional().openapi({
          example: '/data/attributes/username',
        }),
        parameter: z.string().optional().openapi({
          example: 'username',
        }),
        header: z.string().optional().openapi({
          example: 'Authorization',
        }),
      }),
      links: z.object({
        about: z.string().url().openapi({
          example: 'https://api.website.com/docs/errors/INVALID_INPUT',
        }),
        type: z.string().url().openapi({
          example: 'https://api.website.com/docs/errors',
        }),
      }),
    }),
  ),
});

export const invalidInputResponse = (c: Context, errors: ZodIssue[]) => {
  const url = new URL(c.req.url);
  c.status(400);
  return c.json<z.infer<typeof InvalidInputResponseSchema>, 400>({
    errors: errors.map((issue) => ({
      id: nanoid(),
      status: 400,
      code: 'INVALID_INPUT',
      title: 'Invalid Input',
      details: issue.message,
      meta: {
        ZodIssue: issue,
      },
      source: {
        pointer: `/data/${issue.path.join('/')}`,
      },
      links: {
        about: `https://${url.origin}/docs/errors/INVALID_INPUT`,
        type: `https://${url.origin}/docs/errors`,
      },
    })),
  });
};
